package main

import (
	"bytes"
	"encoding/json"
	"errors"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

const (
	maxRequestBodySize  = 4096
	maxResponseBodySize = 1024 * 1024 // 1 MiB
	maxRedirects        = 3
)

var privateIPNets = mustParseCIDRs([]string{
	"127.0.0.0/8",   // loopback
	"10.0.0.0/8",    // private
	"172.16.0.0/12", // private
	"192.168.0.0/16", // private
	"169.254.0.0/16", // link-local
	"::1/128",       // ipv6 loopback
	"fc00::/7",      // unique local
	"fe80::/10",     // link-local
})

func main() {
	// Intentionally left minimal. Register FetchURLPreview in your router/server setup.
}

func mustParseCIDRs(cidrs []string) []*net.IPNet {
	out := make([]*net.IPNet, 0, len(cidrs))
	for _, c := range cidrs {
		_, n, err := net.ParseCIDR(c)
		if err != nil {
			panic(err)
		}
		out = append(out, n)
	}
	return out
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, PreviewResponse{
			Error: "method not allowed",
		})
		return
	}

	if len(ctx.PostBody()) > maxRequestBodySize {
		writeJSON(ctx, fasthttp.StatusRequestEntityTooLarge, PreviewResponse{
			Error: "request body too large",
		})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "invalid JSON",
		})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "url is required",
		})
		return
	}

	parsedURL, err := validateTargetURL(targetURL)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: err.Error(),
		})
		return
	}

	title, description, err := fetchPreview(parsedURL.String())
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: err.Error(),
		})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func validateTargetURL(raw string) (*url.URL, error) {
	u, err := url.Parse(raw)
	if err != nil {
		return nil, errors.New("invalid URL format")
	}

	if u.Scheme != "http" && u.Scheme != "https" {
		return nil, errors.New("URL must use http or https scheme")
	}

	if u.Host == "" {
		return nil, errors.New("URL host is required")
	}

	if u.User != nil {
		return nil, errors.New("userinfo in URL is not allowed")
	}

	hostname := u.Hostname()
	if hostname == "" {
		return nil, errors.New("invalid URL host")
	}

	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateOrLocalIP(ip) {
			return nil, errors.New("target host is not allowed")
		}
		return u, nil
	}

	ips, err := net.LookupIP(hostname)
	if err != nil {
		return nil, errors.New("failed to resolve host")
	}
	if len(ips) == 0 {
		return nil, errors.New("host did not resolve")
	}
	for _, ip := range ips {
		if isPrivateOrLocalIP(ip) {
			return nil, errors.New("target host is not allowed")
		}
	}

	return u, nil
