func isPrivateOrLocalIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	for _, n := range privateIPNets {
		if n.Contains(ip) {
			return true
		}
	}

	if ip.IsUnspecified() || ip.IsMulticast() {
		return true
	}

	return false
}

func fetchPreview(targetURL string) (string, string, error) {
	client := &fasthttp.Client{
