func router(ctx *fasthttp.RequestCtx) {
	switch string(ctx.Path()) {
	case "/preview":
		FetchURLPreview(ctx)
	default:
		ctx.SetStatusCode(fasthttp.StatusNotFound)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "not found"})
	}
