	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "url is required"})
		return
	}

	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "invalid url"})
		return
	}

	host := parsedURL.Hostname()
	if host == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "invalid url"})
		return
	}

	if ip := net.ParseIP(host); ip != nil && isPrivateIP(ip) {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "private or local addresses are not allowed"})
		return
	}

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "fasthttp-url-preview/1.0")
	req.Header.Set("Accept", "text/html,application/xhtml+xml")

	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			hostPart, _, err := net.SplitHostPort(addr)
			if err != nil {
				hostPart = addr
			}

			if ip := net.ParseIP(hostPart); ip != nil && isPrivateIP(ip) {
				return nil, fasthttp.ErrDialTimeout
			}

			return fasthttp.DialTimeout(addr, 3*time.Second)
		},
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	if err := client.DoRedirects(req, resp, 5); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "failed to fetch url: " + err.Error()})
		return
	}

	statusCode := resp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "upstream returned non-success status"})
		return
	}

	title, description, err := extractPreview(resp.Body())
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "failed to parse html"})
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	_ = json.NewEncoder(ctx).Encode(previewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	})
