func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	return ip.IsLoopback() ||
		ip.IsPrivate() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsMulticast() ||
		ip.IsUnspecified()
}

func extractPreview(body []byte) (string, string, error) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", "", err
	}

	var title string
	var description string

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			if n.Data == "meta" && description == "" {
				var nameAttr string
				var contentAttr string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					if key == "name" || key == "property" {
						nameAttr = strings.ToLower(val)
					}
					if key == "content" {
						contentAttr = val
					}
				}
				if nameAttr == "description" || nameAttr == "og:description" {
					description = contentAttr
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description, nil
}

