	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		_, _ = ctx.Write([]byte(`{"error":"failed to encode response"}`))
		return
	}
	_, _ = ctx.Write(data)
}

func extractPreview(htmlBody string) (string, string) {
	doc, err := html.Parse(strings.NewReader(htmlBody))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, property, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = strings.ToLower(strings.TrimSpace(attr.Val))
					case "property":
						property = strings.ToLower(strings.TrimSpace(attr.Val))
					case "content":
						content = strings.TrimSpace(attr.Val)
					}
				}

				if description == "" && content != "" {
					if name == "description" || property == "og:description" {
						description = content
					}
				}
			}
		}

		for child := n.FirstChild; child != nil; child = child.NextSibling {
			walk(child)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, errorResponse{
			Error: "method not allowed",
		})
		return
	}

	var reqBody fetchRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "invalid JSON body",
		})
		return
	}

	reqBody.URL = strings.TrimSpace(reqBody.URL)
	if reqBody.URL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "url is required",
		})
		return
	}

	if !strings.HasPrefix(strings.ToLower(reqBody.URL), "http://") && !strings.HasPrefix(strings.ToLower(reqBody.URL), "https://") {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "url must start with http:// or https://",
		})
		return
	}

	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxConnWaitTimeout:  5 * time.Second,
		MaxIdleConnDuration: 30 * time.Second,
	}

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")

	if err := client.DoRedirects(req, resp, 5); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "failed to fetch URL: " + err.Error(),
		})
		return
	}

	statusCode := resp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "upstream returned non-success status",
		})
		return
	}

	body := string(resp.Body())
	title, description := extractPreview(body)

	writeJSON(ctx, fasthttp.StatusOK, previewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	})
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			writeJSON(ctx, fasthttp.StatusNotFound, errorResponse{
				Error: "not found",
			})
		}
	}

	log.Println("Server listening on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatalf("server failed: %v", err)
	}
}

