package main

import (
	"encoding/json"
	"log"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type fetchRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

type errorResponse struct {
	Error string `json:"error"`
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", router); err != nil {
		log.Fatalf("server failed: %v", err)
	}
}

func router(ctx *fasthttp.RequestCtx) {
	switch string(ctx.Path()) {
	case "/preview":
		FetchURLPreview(ctx)
	default:
		ctx.SetStatusCode(fasthttp.StatusNotFound)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "not found"})
	}
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "method not allowed"})
		return
	}

	var reqBody fetchRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "invalid JSON body"})
		return
	}

	reqBody.URL = strings.TrimSpace(reqBody.URL)
	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "url is required"})
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")

	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "failed to fetch URL: " + err.Error()})
		return
	}

	statusCode := resp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "upstream returned non-success status"})
		return
	}

	title, description, err := extractPreview(resp.Body())
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		_ = json.NewEncoder(ctx).Encode(errorResponse{Error: "failed to parse HTML: " + err.Error()})
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json")
	_ = json.NewEncoder(ctx).Encode(previewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	})
}

func extractPreview(body []byte) (string, string, error) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", "", err
	}

	var title string
	var description string

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			}

			if n.Data == "meta" && description == "" {
				var name string
				var content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name", "property":
						name = strings.ToLower(strings.TrimSpace(attr.Val))
					case "content":
						content = strings.TrimSpace(attr.Val)
					}
				}
				if name == "description" || name == "og:description" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description, nil
}

