package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, PreviewResponse{
			Error: "Method not allowed",
		})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON",
		})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "URL is required",
		})
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil || parsedURL.Host == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "Invalid URL format",
		})
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "URL must use http or https scheme",
		})
		return
	}

	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	reqHTTP := fasthttp.AcquireRequest()
	resHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(resHTTP)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod(fasthttp.MethodGet)
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")
	reqHTTP.Header.Set("Accept", "text/html,application/xhtml+xml")

	const maxRedirects = 10
	if err := client.DoRedirects(reqHTTP, resHTTP, maxRedirects); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	if resHTTP.StatusCode() != fasthttp.StatusOK {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: fmt.Sprintf("Unexpected status code: %d", resHTTP.StatusCode()),
		})
		return
	}

	bodyBytes := resHTTP.Body()
	if len(bodyBytes) == 0 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "Empty response body",
		})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusInternalServerError, PreviewResponse{
			Error: fmt.Sprintf("Failed to parse HTML: %v", err),
		})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, property, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					switch key {
					case "name":
						name = strings.ToLower(val)
					case "property":
						property = strings.ToLower(val)
					case "content":
						content = val
					}
				}

				if description == "" && content != "" {
					if name == "description" || property == "og:description" {
						description = content
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
		}
	}

	walk(doc)

	return title, description, nil
}

func writeJSON(ctx *fasthttp.RequestCtx, statusCode int, resp PreviewResponse) {
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")

	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json; charset=utf-8")
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{
			Error: "Failed to encode response",
		})
	}
}

