// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

const (
	maxRequestBodySize  = 4096
	maxResponseBodySize = 1024 * 1024 // 1 MiB
	maxRedirects        = 3
)

var privateIPNets []*net.IPNet

func init() {
	cidrs := []string{
		"127.0.0.0/8",    // loopback
		"10.0.0.0/8",     // private
		"172.16.0.0/12",  // private
		"192.168.0.0/16", // private
		"169.254.0.0/16", // link-local
		"::1/128",        // IPv6 loopback
		"fc00::/7",       // unique local
		"fe80::/10",      // link-local
	}
	for _, cidr := range cidrs {
		_, network, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPNets = append(privateIPNets, network)
		}
	}
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, resp PreviewResponse) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")
	_ = json.NewEncoder(ctx).Encode(resp)
}

func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return true
	}
	for _, network := range privateIPNets {
		if network.Contains(ip) {
			return true
		}
	}
	return ip.IsUnspecified() || ip.IsMulticast()
}

func validateTargetURL(raw string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(raw)
	if err != nil {
		return nil, errors.New("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("URL must use http or https scheme")
	}

	if parsedURL.Hostname() == "" {
		return nil, errors.New("URL host is required")
	}

	if parsedURL.User != nil {
		return nil, errors.New("URL userinfo is not allowed")
	}

	return parsedURL, nil
}

func resolveAndValidateHost(hostname string) error {
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return errors.New("failed to resolve host")
	}
	if len(ips) == 0 {
		return errors.New("host did not resolve to any IP")
	}
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return errors.New("target resolves to a disallowed IP address")
		}
	}
	return nil
}

func secureDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	if port != "80" && port != "443" {
		return nil, errors.New("disallowed port")
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}
	if len(ips) == 0 {
		return nil, errors.New("no IPs resolved")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, errors.New("disallowed target IP")
		}
	}

	dialer := &net.Dialer{
		Timeout: 5 * time.Second,
	}
	return dialer.Dial("tcp", addr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, PreviewResponse{
			Error: "Method not allowed",
		})
		return
	}

	if len(ctx.PostBody()) > maxRequestBodySize {
		writeJSON(ctx, fasthttp.StatusRequestEntityTooLarge, PreviewResponse{
			Error: "Request body too large",
		})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON",
		})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "URL is required",
		})
		return
	}

	parsedURL, err := validateTargetURL(targetURL)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: err.Error(),
		})
		return
	}

	if err := resolveAndValidateHost(parsedURL.Hostname()); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "URL target is not allowed",
		})
		return
	}

	client := &fasthttp.Client{
		Dial:                secureDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: maxResponseBodySize,
		NoDefaultUserAgentHeader: true,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml")
	freq.Header.Set("Connection", "close")

	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "Failed to fetch URL",
		})
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "Unexpected status code",
		})
		return
	}

	contentType := strings.ToLower(string(res.Header.ContentType()))
	if contentType != "" && !strings.Contains(contentType, "text/html") && !strings.Contains(contentType, "application/xhtml+xml") {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "URL did not return HTML content",
		})
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "Empty response body",
		})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusInternalServerError, PreviewResponse{
			Error: "Failed to parse HTML",
		})
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	writeJSON(ctx, fasthttp.StatusOK, resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil {
			return
		}

		if n.Type == html.ElementNode && n.Data == "title" && title == "" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
		}

		if n.Type == html.ElementNode && n.Data == "meta" && description == "" {
			var name, content string
			for _, attr := range n.Attr {
				switch strings.ToLower(attr.Key) {
				case "name", "property":
					name = strings.ToLower(strings.TrimSpace(attr.Val))
				case "content":
					content = strings.TrimSpace(attr.Val)
				}
			}
			if name == "description" || name == "og:description" {
				description = content
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
		}
	}

	walk(doc)
	return title, description, nil
}

