		writeJSONError(ctx, fasthttp.StatusBadRequest, "URL is required")
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		writeJSONError(ctx, fasthttp.StatusBadRequest, "Invalid URL format")
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		writeJSONError(ctx, fasthttp.StatusBadRequest, "URL must use http or https scheme")
