		writeJSONError(ctx, fasthttp.StatusBadRequest, err.Error())
		return
	}

	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		NoDefaultUserAgentHeader: true,
		Dial: func(addr string) (net.Conn, error) {
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				host = addr
			}

			if err := validateResolvedHost(host); err != nil {
				return nil, err
			}

			dialer := &net.Dialer{
				Timeout: 5 * time.Second,
			}
			return dialer.Dial("tcp", addr)
		},
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml")

	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
