					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, property, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					switch key {
					case "name":
						name = strings.ToLower(val)
					case "property":
						property = strings.ToLower(val)
					case "content":
						content = val
					}
				}
				if description == "" && content != "" {
					if name == "description" || property == "og:description" {
						description = content
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, errorResponse{
			Error: "method not allowed",
		})
		return
	}

	var req previewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "invalid JSON body",
		})
		return
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "url is required",
		})
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	var request fasthttp.Request
	var response fasthttp.Response

	request.SetRequestURI(req.URL)
	request.Header.SetMethod(fasthttp.MethodGet)
	request.Header.Set("User-Agent", "url-preview-fetcher/1.0")

	done := make(chan error, 1)
	go func() {
		done <- client.DoRedirects(&request, &response, 10)
	}()

	select {
	case err := <-done:
