package main

import (
	"encoding/json"
	"log"
	"strings"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type previewRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	URL         string `json:"url"`
}

type errorResponse struct {
	Error string `json:"error"`
}

func writeJSON(ctx *fasthttp.RequestCtx, statusCode int, v any) {
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")

	data, err := json.Marshal(v)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"failed to encode response"}`)
		return
	}
	ctx.SetBody(data)
}

func extractPreview(htmlContent string) (string, string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name string
				var content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					switch key {
					case "name", "property":
						name = strings.ToLower(val)
					case "content":
						content = val
					}
				}
				if description == "" && (name == "description" || name == "og:description") {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, errorResponse{
			Error: "method not allowed",
		})
		return
	}

	var reqBody previewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "invalid JSON body",
		})
		return
	}

	reqBody.URL = strings.TrimSpace(reqBody.URL)
	if reqBody.URL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "url is required",
		})
		return
	}

	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")

	if err := client.DoRedirects(req, resp, 10); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "failed to fetch URL: " + err.Error(),
		})
		return
	}

	statusCode := resp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "upstream returned non-2xx status",
		})
		return
	}

	body := string(resp.Body())
	title, description := extractPreview(body)

	writeJSON(ctx, fasthttp.StatusOK, previewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	})
}

func main() {
	router := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			writeJSON(ctx, fasthttp.StatusNotFound, errorResponse{
				Error: "not found",
			})
		}
	}

	log.Println("Server listening on :8080")
	if err := fasthttp.ListenAndServe(":8080", router); err != nil {
		log.Fatal(err)
	}
}

