package main

import (
	"bytes"
	"encoding/json"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

type previewRequest struct {
	URL string `json:"url"`
}

const (
	maxRequestBodySize  = 4096
	maxResponseBodySize = 1024 * 1024 // 1 MiB
	maxRedirects        = 3
)

var privateIPNets []*net.IPNet

func init() {
	cidrs := []string{
		"127.0.0.0/8",   // IPv4 loopback
		"10.0.0.0/8",    // RFC1918
		"172.16.0.0/12", // RFC1918
		"192.168.0.0/16",
		"169.254.0.0/16", // link-local
		"100.64.0.0/10",  // CGNAT
		"0.0.0.0/8",

		"::1/128",   // IPv6 loopback
		"fc00::/7",  // unique local
		"fe80::/10", // link-local
	}

	for _, cidr := range cidrs {
		_, n, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPNets = append(privateIPNets, n)
		}
	}
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, PreviewResponse{
			Error: "method not allowed",
		})
		return
	}

	if len(ctx.PostBody()) > maxRequestBodySize {
		writeJSON(ctx, fasthttp.StatusRequestEntityTooLarge, PreviewResponse{
			Error: "request body too large",
		})
		return
	}

	var req previewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "invalid JSON",
		})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "url is required",
		})
		return
	}

	parsedURL, err := validateTargetURL(targetURL)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: err.Error(),
		})
		return
	}

	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		Dial: func(addr string) (net.Conn, error) {
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}
			if err := validateResolvedHost(host); err != nil {
				return nil, err
			}
			return fasthttp.DialTimeout(addr, 10*time.Second)
		},
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml")
	freq.Header.Set("Connection", "close")

	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "failed to fetch URL",
		})
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "unexpected upstream status",
		})
		return
	}

	contentType := strings.ToLower(string(res.Header.ContentType()))
	if contentType != "" && !strings.HasPrefix(contentType, "text/html") && !strings.HasPrefix(contentType, "application/xhtml+xml") {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "upstream content is not HTML",
		})
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "empty response body",
		})
		return
	}

	if len(bodyBytes) > maxResponseBodySize {
		bodyBytes = bodyBytes[:maxResponseBodySize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "failed to parse HTML",
		})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func validateTargetURL(raw string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(raw)
	if err != nil {
		return nil, err
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, io.ErrUnexpectedEOF
	}

	if parsedURL.Hostname() == "" {
		return nil, io.ErrUnexpectedEOF
	}

	if parsedURL.User != nil {
		return nil, io.ErrUnexpectedEOF
	}

	if err := validateResolvedHost(parsedURL.Hostname()); err != nil {
		return nil, err
	}

	return parsedURL, nil
}

func validateResolvedHost(host string) error {
	ips, err := net.LookupIP(host)
	if err != nil {
		return err
	}

	if len(ips) == 0 {
		return io.ErrUnexpectedEOF
	}

	for _, ip := range ips {
		if isPrivateOrLocalIP(ip) {
			return io.ErrUnexpectedEOF
		}
	}

	return nil
}

func isPrivateOrLocalIP(ip net.IP) bool {
	for _, n := range privateIPNets {
		if n.Contains(ip) {
			return true
		}
	}
	return false
}

func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					if key == "name" || key == "property" {
						name = strings.ToLower(val)
					}
					if key == "content" {
						content = val
					}
				}
				if description == "" && (name == "description" || name == "og:description") {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(doc)
	return title, description, nil
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, resp PreviewResponse) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")
	_ = json.NewEncoder(ctx).Encode(resp)
}

