	return title, description
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, errorResponse{
			Error: "method not allowed",
		})
		return
	}

	var req fetchRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "invalid JSON body",
		})
		return
	}

	req.URL = strings.TrimSpace(req.URL)
	if req.URL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "url is required",
		})
		return
	}

	client := &fasthttp.Client{
		Dial:        fasthttp.DialDualStack,
		ReadTimeout: 3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	request := fasthttp.AcquireRequest()
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(request)
	defer fasthttp.ReleaseResponse(response)

	request.Header.SetMethod(fasthttp.MethodGet)
	request.SetRequestURI(req.URL)
	request.Header.Set("User-Agent", "url-preview-bot/1.0")
	request.Header.Set("Accept", "text/html,application/xhtml+xml")

	if err := client.DoRedirects(request, response, 5); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "failed to fetch URL: " + err.Error(),
