		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "upstream returned non-success status",
		})
		return
	}

	body := string(response.Body())
	title, description := extractPreview(body)

	writeJSON(ctx, fasthttp.StatusOK, previewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

