package main

import (
	"bytes"
	"encoding/json"
	"errors"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

const (
	maxRequestBodySize  = 4096
	maxResponseBodySize = 1024 * 1024 // 1 MiB
	maxRedirects        = 3
)

var privateIPNets []*net.IPNet

func init() {
	cidrs := []string{
		"127.0.0.0/8",    // loopback
		"10.0.0.0/8",     // private
		"172.16.0.0/12",  // private
		"192.168.0.0/16", // private
		"169.254.0.0/16", // link-local
		"::1/128",        // ipv6 loopback
		"fc00::/7",       // unique local
		"fe80::/10",      // ipv6 link-local
	}
	for _, cidr := range cidrs {
		_, ipnet, err := net.ParseCIDR(cidr)
		if err == nil {
			privateIPNets = append(privateIPNets, ipnet)
		}
	}
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, PreviewResponse{
			Error: "method not allowed",
		})
		return
	}

	if len(ctx.PostBody()) > maxRequestBodySize {
		writeJSON(ctx, fasthttp.StatusRequestEntityTooLarge, PreviewResponse{
			Error: "request body too large",
		})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "invalid JSON",
		})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "url is required",
		})
		return
	}

	parsedURL, err := validateTargetURL(targetURL)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: err.Error(),
		})
		return
	}

	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		Dial: func(addr string) (net.Conn, error) {
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}
			if err := validateResolvedHost(host); err != nil {
				return nil, err
			}
			return fasthttp.DialTimeout(addr, 10*time.Second)
		},
	}

	bodyBytes, err := fetchURL(client, parsedURL.String(), 0)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "failed to fetch URL",
		})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "failed to parse HTML",
		})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func fetchURL(client *fasthttp.Client, target string, redirectCount int) ([]byte, error) {
	if redirectCount > maxRedirects {
		return nil, errors.New("too many redirects")
	}

	req := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(target)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")
	req.Header.Set("Accept", "text/html,application/xhtml+xml")

	if err := client.Do(req, res); err != nil {
		return nil, err
	}

	statusCode := res.StatusCode()
	switch statusCode {
	case fasthttp.StatusMovedPermanently,
		fasthttp.StatusFound,
		fasthttp.StatusSeeOther,
		fasthttp.StatusTemporaryRedirect,
		fasthttp.StatusPermanentRedirect:
		location := string(res.Header.Peek("Location"))
		if location == "" {
			return nil, errors.New("redirect without location")
		}

		baseURL, err := url.Parse(target)
		if err != nil {
			return nil, err
		}
		nextURL, err := baseURL.Parse(location)
		if err != nil {
			return nil, err
		}
		validated, err := validateTargetURL(nextURL.String())
		if err != nil {
			return nil, err
		}
		return fetchURL(client, validated.String(), redirectCount+1)

	case fasthttp.StatusOK:
		// continue
	default:
		return nil, errors.New("unexpected status code")
	}

	contentType := strings.ToLower(string(res.Header.ContentType()))
	if !strings.HasPrefix(contentType, "text/html") && !strings.HasPrefix(contentType, "application/xhtml+xml") {
		return nil, errors.New("unsupported content type")
	}

	body := res.Body()
	if len(body) == 0 {
		return nil, errors.New("empty response body")
	}
	if len(body) > maxResponseBodySize {
		return nil, errors.New("response body too large")
	}

	out := make([]byte, len(body))
	copy(out, body)
	return out, nil
}

func validateTargetURL(raw string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(raw)
	if err != nil {
		return nil, errors.New("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("URL must use http or https scheme")
	}

	if parsedURL.Hostname() == "" {
		return nil, errors.New("URL must include a valid host")
	}

	if parsedURL.User != nil {
		return nil, errors.New("URL must not contain user info")
	}

	if err := validateResolvedHost(parsedURL.Hostname()); err != nil {
		return nil, errors.New("URL host is not allowed")
	}

	return parsedURL, nil
}

func validateResolvedHost(host string) error {
	ips, err := net.LookupIP(host)
	if err != nil {
		return err
	}
	if len(ips) == 0 {
		return errors.New("host did not resolve")
	}

	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return errors.New("disallowed IP")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	for _, ipnet := range privateIPNets {
		if ipnet.Contains(ip) {
			return true
		}
	}
	return ip.IsUnspecified() || ip.IsMulticast()
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, resp PreviewResponse) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")
	_ = json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(io.LimitReader(r, maxResponseBodySize))

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if errors.Is(z.Err(), io.EOF) {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			tok := z.Token()
			tagName := strings.ToLower(tok.Data)

			if tagName == "title" && title == "" {
				if z.Next() == html.TextToken {
					title = sanitizeText(string(z.Text()))
				}
				continue
			}

			if tagName == "meta" && description == "" {
				var name, content string
				for _, attr := range tok.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					switch key {
					case "name", "property":
						name = strings.ToLower(val)
					case "content":
						content = val
					}
				}
				if name == "description" || name == "og:description" {
					description = sanitizeText(content)
				}
			}
		}

		if title != "" && description != "" {
			return title, description, nil
		}
	}
}

func sanitizeText(s string) string {
	s = html.UnescapeString(s)
	return strings.Join(strings.Fields(s), " ")
}

func main() {
	// Intentionally left minimal.
}

