package main

import (
	"bytes"
	"encoding/json"
	"io"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, PreviewResponse{
			Error: "Method not allowed",
		})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "Invalid JSON",
		})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "URL is required",
		})
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil || parsedURL.Host == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "Invalid URL format",
		})
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "URL must use http or https scheme",
		})
		return
	}

	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	reqHTTP := fasthttp.AcquireRequest()
	respHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(respHTTP)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod(fasthttp.MethodGet)
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")
	reqHTTP.Header.Set("Accept", "text/html,application/xhtml+xml")

	if err := client.DoRedirects(reqHTTP, respHTTP, 10); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
		return
	}

	if respHTTP.StatusCode() < 200 || respHTTP.StatusCode() >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "Unexpected status code",
		})
		return
	}

	bodyBytes := respHTTP.Body()
	if len(bodyBytes) == 0 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "Empty response body",
		})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusInternalServerError, PreviewResponse{
			Error: "Failed to parse HTML: " + err.Error(),
		})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil {
			return
		}

		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			if n.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name", "property":
						name = strings.ToLower(strings.TrimSpace(attr.Val))
					case "content":
						content = strings.TrimSpace(attr.Val)
					}
				}

				if name == "description" || name == "og:description" || name == "twitter:description" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
		}
	}

	walk(doc)
	return title, description, nil
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, resp PreviewResponse) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")

	data, err := json.Marshal(resp)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"Failed to encode response"}`)
		return
	}

	ctx.SetBody(data)
}

func main() {
	// Example:
	// fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

