// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, PreviewResponse{
			Error: "method not allowed",
		})
		return
	}

	if len(ctx.PostBody()) > maxRequestBodySize {
		writeJSON(ctx, fasthttp.StatusRequestEntityTooLarge, PreviewResponse{
			Error: "request body too large",
		})
		return
	}

