	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "invalid JSON",
		})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: "url is required",
		})
		return
	}

	parsedURL, err := validateTargetURL(targetURL)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: err.Error(),
		})
		return
	}

	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		NoDefaultUserAgentHeader: true,
		Dial: func(addr string) (net.Conn, error) {
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}
			if err := validateResolvedHost(host); err != nil {
				return nil, err
			}
			return fasthttp.DialTimeout(addr, 10*time.Second)
		},
	}

	reqHTTP := fasthttp.AcquireRequest()
	resHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(resHTTP)

	reqHTTP.SetRequestURI(parsedURL.String())
	reqHTTP.Header.SetMethod(fasthttp.MethodGet)
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")
	reqHTTP.Header.Set("Accept", "text/html,application/xhtml+xml")

	if err := client.DoRedirects(reqHTTP, resHTTP, maxRedirects); err != nil {
		status := fasthttp.StatusBadGateway
		if errors.Is(err, errPrivateAddress) {
			status = fasthttp.StatusBadRequest
		}
		writeJSON(ctx, status, PreviewResponse{
			Error: "failed to fetch URL",
		})
		return
	}

	if err := validateFinalResponseURL(resHTTP); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, PreviewResponse{
			Error: err.Error(),
		})
		return
	}

	if resHTTP.StatusCode() != fasthttp.StatusOK {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "unexpected upstream status",
		})
		return
	}

	contentType := strings.ToLower(string(resHTTP.Header.ContentType()))
	if contentType != "" && !strings.HasPrefix(contentType, "text/html") && !strings.HasPrefix(contentType, "application/xhtml+xml") {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "upstream content is not HTML",
		})
		return
	}

	bodyBytes := resHTTP.Body()
	if len(bodyBytes) == 0 {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "empty response body",
		})
		return
	}
	if len(bodyBytes) > maxResponseBodySize {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "response body too large",
		})
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusInternalServerError, PreviewResponse{
			Error: "failed to parse HTML",
		})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, resp PreviewResponse) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")
	_ = json.NewEncoder(ctx).Encode(resp)
}

func validateTargetURL(raw string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(raw)
	if err != nil {
		return nil, errors.New("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errors.New("URL must use http or https scheme")
	}

	if parsedURL.Hostname() == "" {
		return nil, errors.New("URL must include a valid host")
	}

	if parsedURL.User != nil {
		return nil, errors.New("URL must not contain user info")
	}

	if err := validateResolvedHost(parsedURL.Hostname()); err != nil {
		if errors.Is(err, errPrivateAddress) {
			return nil, errors.New("URL points to a restricted address")
		}
		return nil, errors.New("unable to resolve host")
	}

	return parsedURL, nil
}

func validateFinalResponseURL(res *fasthttp.Response) error {
	finalURI := res.Header.Peek("Location")
	if len(finalURI) == 0 {
		return nil
	}
	u, err := url.Parse(string(finalURI))
	if err != nil {
		return errors.New("invalid redirect target")
	}
	if u.Hostname() == "" {
		return nil
	}
	if u.Scheme != "" && u.Scheme != "http" && u.Scheme != "https" {
		return errors.New("redirected to unsupported scheme")
	}
	if err := validateResolvedHost(u.Hostname()); err != nil {
		return errors.New("redirected to a restricted address")
	}
	return nil
}

func validateResolvedHost(host string) error {
	ips, err := net.LookupIP(host)
	if err != nil {
		return err
	}
	if len(ips) == 0 {
		return errors.New("no IPs resolved")
	}
	for _, ip := range ips {
		if isRestrictedIP(ip) {
			return errPrivateAddress
		}
	}
	return nil
}

func isRestrictedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsMulticast() {
		return true
	}

	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return true
		case ip4[0] == 127:
			return true
		case ip4[0] == 169 && ip4[1] == 254:
			return true
		case ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31:
			return true
		case ip4[0] == 192 && ip4[1] == 168:
			return true
		case ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127:
			return true
		case ip4[0] == 0:
			return true
		default:
			return false
		}
	}

	if len(ip) == net.IPv6len {
		if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
		// fc00::/7 unique local addresses
		if ip[0]&0xfe == 0xfc {
			return true
		}
		// :: unspecified
		if ip.IsUnspecified() {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	root, err := html.Parse(io.LimitReader(r, maxResponseBodySize))
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n == nil || (title != "" && description != "") {
			return
		}

		if n.Type == html.ElementNode {
			switch strings.ToLower(n.Data) {
			case "title":
				if title == "" && n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					switch key {
					case "name", "property":
						name = strings.ToLower(val)
					case "content":
						content = val
					}
				}
				if description == "" && (name == "description" || name == "og:description") {
					description = content
				}
			}
		}

		for child := n.FirstChild; child != nil; child = child.NextSibling {
			walk(child)
			if title != "" && description != "" {
				return
			}
		}
	}

	walk(root)
	return title, description, nil
}

