		case ip4[0] == 192 && ip4[1] == 168:
			return true
		case ip4[0] == 127:
			return true
		case ip4[0] == 169 && ip4[1] == 254:
			return true
		case ip4[0] == 0:
			return true
		}
		return false
	}

	if ip.IsPrivate() {
		return true
	}

	return false
}

func validateAndResolveURL(raw string) (*url.URL, string, error) {
	parsed, err := url.Parse(raw)
	if err != nil {
		return nil, "", errors.New("invalid URL")
	}

	scheme := strings.ToLower(parsed.Scheme)
	if scheme != "http" && scheme != "https" {
		return nil, "", errors.New("only http and https URLs are allowed")
	}

	if parsed.Host == "" {
		return nil, "", errors.New("invalid URL host")
	}

	host := parsed.Hostname()
	if host == "" {
		return nil, "", errors.New("invalid URL host")
	}

	port := parsed.Port()
	if port == "" {
		if scheme == "https" {
			port = "443"
		} else {
			port = "80"
		}
	}

	ips, err := net.LookupIP(host)
	if err != nil || len(ips) == 0 {
		return nil, "", errors.New("failed to resolve host")
	}

	var selectedIP net.IP
	for _, ip := range ips {
		if isBlockedIP(ip) {
			return nil, "", errors.New("target host is not allowed")
		}
		if selectedIP == nil {
			selectedIP = ip
		}
	}

	if selectedIP == nil {
		return nil, "", errors.New("failed to resolve host")
	}

	return parsed, net.JoinHostPort(selectedIP.String(), port), nil
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		writeJSON(ctx, fasthttp.StatusMethodNotAllowed, errorResponse{
			Error: "method not allowed",
		})
		return
	}

	var reqBody previewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "invalid JSON body",
		})
		return
	}

	reqBody.URL = strings.TrimSpace(reqBody.URL)
	if reqBody.URL == "" {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: "url is required",
		})
		return
	}

	parsedURL, dialAddr, err := validateAndResolveURL(reqBody.URL)
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadRequest, errorResponse{
			Error: err.Error(),
		})
		return
	}

	client := &fasthttp.Client{
		ReadTimeout:                   3 * time.Second,
		WriteTimeout:                  3 * time.Second,
		DisableHeaderNamesNormalizing: false,
		Dial: func(addr string) (net.Conn, error) {
			d := net.Dialer{Timeout: 3 * time.Second}
			return d.DialContext(context.Background(), "tcp", dialAddr)
		},
	}

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(parsedURL.String())
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "url-preview-bot/1.0")
	req.Header.Set("Accept", "text/html,application/xhtml+xml")

	if err := client.DoRedirects(req, resp, 0); err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "failed to fetch URL: " + err.Error(),
		})
		return
	}

	statusCode := resp.StatusCode()
	if statusCode < 200 || statusCode >= 300 {
		writeJSON(ctx, fasthttp.StatusBadGateway, errorResponse{
			Error: "upstream returned non-success status",
		})
		return
	}

	body := string(resp.Body())
	title, description := extractPreview(body)

	writeJSON(ctx, fasthttp.StatusOK, previewResponse{
		Title:       title,
		Description: description,
		URL:         reqBody.URL,
	})
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			writeJSON(ctx, fasthttp.StatusNotFound, errorResponse{
				Error: "not found",
			})
		}
	}

	log.Println("server listening on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatal(err)
	}
}

