	respHTTP := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(reqHTTP)
	defer fasthttp.ReleaseResponse(respHTTP)

	reqHTTP.SetRequestURI(targetURL)
	reqHTTP.Header.SetMethod(fasthttp.MethodGet)
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")
	reqHTTP.Header.Set("Accept", "text/html,application/xhtml+xml")

