	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		writeJSON(ctx, fasthttp.StatusBadGateway, PreviewResponse{
			Error: "failed to parse HTML",
		})
		return
	}

	writeJSON(ctx, fasthttp.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func writeJSON(ctx *fasthttp.RequestCtx, status int, resp PreviewResponse) {
	ctx.SetStatusCode(status)
	ctx.SetContentType("application/json; charset=utf-8")
	_ = json.NewEncoder(ctx).Encode(resp)
}

func validateTargetURL(raw string) (*url.URL, error) {
	parsedURL, err := url.ParseRequestURI(raw)
	if err != nil {
		return nil, err
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, errInvalidURL("url must use http or https scheme")
	}

	if parsedURL.Hostname() == "" {
		return nil, errInvalidURL("url must include a valid host")
	}

	if parsedURL.User != nil {
		return nil, errInvalidURL("userinfo is not allowed in url")
	}

	ips, err := net.LookupIP(parsedURL.Hostname())
	if err != nil {
		return nil, errInvalidURL("unable to resolve host")
	}

	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return nil, errInvalidURL("target host resolves to a disallowed address")
		}
	}

	return parsedURL, nil
}

func fetchURLContent(targetURL string) ([]byte, error) {
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			for _, ip := range ips {
				if isDisallowedIP(ip) {
					return nil, errInvalidURL("connection to disallowed address")
				}
			}

			dialer := &net.Dialer{
				Timeout: 5 * time.Second,
			}
			return dialer.Dial("tcp", net.JoinHostPort(host, port))
		},
		ReadTimeout:                   10 * time.Second,
		WriteTimeout:                  10 * time.Second,
		MaxIdleConnDuration:           10 * time.Second,
		MaxConnsPerHost:               10,
		NoDefaultUserAgentHeader:      true,
		DisableHeaderNamesNormalizing: true,
	}

	req := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(targetURL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")
	req.Header.Set("Accept", "text/html,application/xhtml+xml")

	if err := client.DoRedirects(req, res, maxRedirects); err != nil {
		return nil, err
	}

	if res.StatusCode() != fasthttp.StatusOK {
		return nil, errInvalidURL("unexpected status code")
	}

	contentType := strings.ToLower(string(res.Header.ContentType()))
	if contentType != "" && !strings.Contains(contentType, "text/html") && !strings.Contains(contentType, "application/xhtml+xml") {
		return nil, errInvalidURL("unsupported content type")
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		return nil, errInvalidURL("empty response body")
	}

	if len(bodyBytes) > maxResponseBodySize {
		return nil, errInvalidURL("response body too large")
	}

	copied := make([]byte, len(bodyBytes))
	copy(copied, bodyBytes)
	return copied, nil
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(io.LimitReader(r, maxResponseBodySize))

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			tagName := strings.ToLower(t.Data)

			if tagName == "title" && title == "" {
				if z.Next() == html.TextToken {
					title = sanitizeText(string(z.Text()))
				}
			}

			if tagName == "meta" && description == "" {
				var name, content string
				for _, attr := range t.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.TrimSpace(attr.Val)
					switch key {
					case "name", "property":
						name = strings.ToLower(val)
					case "content":
						content = sanitizeText(val)
					}
				}

				if name == "description" || name == "og:description" {
					description = content
				}
			}

			if title != "" && description != "" {
				return title, description, nil
			}
		}
	}
}

func sanitizeText(s string) string {
	return strings.Join(strings.Fields(strings.TrimSpace(s)), " ")
}

func isDisallowedIP(ip net.IP) bool {
	if ip == nil {
		return true
	}

	for _, network := range privateIPNets {
		if network.Contains(ip) {
			return true
		}
	}

	if ip.IsUnspecified() || ip.IsMulticast() {
		return true
	}

	return false
}

func mustParseCIDRs(cidrs []string) []*net.IPNet {
	nets := make([]*net.IPNet, 0, len(cidrs))
	for _, cidr := range cidrs {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			panic(err)
		}
		nets = append(nets, network)
	}
	return nets
}

type invalidURLError string

func (e invalidURLError) Error() string {
	return string(e)
}

func errInvalidURL(msg string) error {
	return invalidURLError(msg)
}

